254	func createCompareWorktree(workDir, compareID, harnessName string) (string, error) {
255		gitRoot, err := resolveGitRoot(workDir)
256		if err != nil {
257			return "", fmt.Errorf("resolving git root: %w", err)
258		}
259		wtDir := filepath.Join(gitRoot, ".worktrees", fmt.Sprintf("%s-%s", compareID, harnessName))
260		cmd := exec.Command("git", "worktree", "add", "--detach", wtDir, "HEAD")
261		cmd.Dir = gitRoot
262		cmd.Env = cleanGitEnv()
263		if out, err := cmd.CombinedOutput(); err != nil {
264			return "", fmt.Errorf("git worktree add: %s\n%s", err, string(out))
265		}
266		return wtDir, nil
267	}
