269	func resolveGitRoot(dir string) (string, error) {
270		cmd := exec.Command("git", "rev-parse", "--show-toplevel")
271		cmd.Dir = dir
272		cmd.Env = cleanGitEnv()
273		out, err := cmd.Output()
274		if err != nil {
275			return "", fmt.Errorf("not a git repository: %s", dir)
276		}
277		return strings.TrimSpace(string(out)), nil
278	}
