280	func captureGitDiff(worktreePath string) string {
281		cmd := exec.Command("git", "diff", "HEAD")
282		cmd.Dir = worktreePath
283		cmd.Env = cleanGitEnv()
284		out, err := cmd.Output()
285		if err != nil {
286			return ""
287		}
288		diff := string(out)
289	
290		cmd3 := exec.Command("git", "ls-files", "--others", "--exclude-standard")
291		cmd3.Dir = worktreePath
292		cmd3.Env = cleanGitEnv()
293		untrackedOut, _ := cmd3.Output()
294		untracked := strings.TrimSpace(string(untrackedOut))
295		if untracked != "" {
296			for _, f := range strings.Split(untracked, "\n") {
297				f = strings.TrimSpace(f)
298				if f == "" {
299					continue
300				}
301				content, err := os.ReadFile(filepath.Join(worktreePath, f))
302				if err != nil {
303					continue
304				}
305				diff += fmt.Sprintf("\n--- /dev/null\n+++ b/%s\n@@ -0,0 +1 @@\n", f)
306				for _, line := range strings.Split(string(content), "\n") {
307					if line != "" || len(content) > 0 {
308						diff += "+" + line + "\n"
309					}
310				}
311			}
312		}
313		return strings.TrimSpace(diff)
314	}
