316	// cleanGitEnv returns the current environment with git hook-specific vars removed.
317	func cleanGitEnv() []string {
318		blocked := map[string]bool{
319			"GIT_DIR":                          true,
320			"GIT_INDEX_FILE":                   true,
321			"GIT_WORK_TREE":                    true,
322			"GIT_OBJECT_DIRECTORY":             true,
323			"GIT_ALTERNATE_OBJECT_DIRECTORIES": true,
324		}
325		env := os.Environ()
326		out := make([]string, 0, len(env))
327		for _, e := range env {
328			key := e
329			if i := strings.Index(e, "="); i >= 0 {
330				key = e[:i]
331			}
332			if !blocked[key] {
333				out = append(out, e)
334			}
335		}
336		return out
337	}
