346	// cleanupCompareWorktrees removes the worktrees created for a compare run.
347	// Free function; both RunCompareViaService and RunCompareWithAgent route through
348	// this helper.
349	func cleanupCompareWorktrees(repoDir, compareID string) {
350		if root, err := resolveGitRoot(repoDir); err == nil {
351			repoDir = root
352		}
353		wtBase := filepath.Join(repoDir, ".worktrees")
354		entries, err := os.ReadDir(wtBase)
355		if err != nil {
356			return
357		}
358		for _, e := range entries {
359			if e.IsDir() && strings.HasPrefix(e.Name(), compareID) {
360				wtPath := filepath.Join(wtBase, e.Name())
361				cmd := exec.Command("git", "worktree", "remove", "--force", wtPath)
362				cmd.Dir = repoDir
363				cmd.Env = cleanGitEnv()
364				_ = cmd.Run()
365			}
366		}
367		cmd := exec.Command("git", "worktree", "prune")
368		cmd.Dir = repoDir
369		cmd.Env = cleanGitEnv()
370		_ = cmd.Run()
371	}
