379	// RunQuorumWith invokes multiple harnesses concurrently and returns each
380	// result. Production callers should use RunQuorumViaService; tests may pass
381	// Runner.Run.
382	func RunQuorumWith(run RunFunc, opts QuorumOptions) ([]*Result, error) {
383		if len(opts.Harnesses) == 0 {
384			return nil, fmt.Errorf("agent: quorum requires at least one harness")
385		}
386	
387		threshold := effectiveThreshold(opts.Strategy, opts.Threshold, len(opts.Harnesses))
388		if threshold < 1 || threshold > len(opts.Harnesses) {
389			return nil, fmt.Errorf("agent: invalid quorum threshold %d for %d harnesses", threshold, len(opts.Harnesses))
390		}
391	
392		results := make([]*Result, len(opts.Harnesses))
393		var wg sync.WaitGroup
394		var mu sync.Mutex
395		var firstErr error
396	
397		for i, name := range opts.Harnesses {
398			wg.Add(1)
399			go func(idx int, harness string) {
400				defer wg.Done()
401				runOpts := opts.RunOptions
402				runOpts.Harness = harness
403				result, err := run(runOpts)
404				mu.Lock()
405				if err != nil && firstErr == nil {
406					firstErr = err
407				}
408				results[idx] = result
409				mu.Unlock()
410			}(i, name)
411		}
412		wg.Wait()
413	
414		return results, firstErr
415	}
