595	// RunBenchmarkWith executes all prompts in a suite against all arms via the
596	// runCompare closure. Production callers should use RunBenchmarkViaService.
597	func RunBenchmarkWith(runCompare func(CompareOptions) (*ComparisonRecord, error), suite *BenchmarkSuite) (*BenchmarkResult, error) {
598		result := &BenchmarkResult{
599			Suite:     suite.Name,
600			Version:   suite.Version,
601			Timestamp: time.Now().UTC(),
602			Arms:      suite.Arms,
603		}
604	
605		var timeout time.Duration
606		if suite.Timeout != "" {
607			var err error
608			timeout, err = time.ParseDuration(suite.Timeout)
609			if err != nil {
610				return nil, fmt.Errorf("invalid timeout %q: %w", suite.Timeout, err)
611			}
612		}
613	
614		for _, prompt := range suite.Prompts {
615			promptText := prompt.Prompt
616			if promptText == "" && prompt.PromptFile != "" {
617				data, err := os.ReadFile(prompt.PromptFile)
618				if err != nil {
619					return nil, fmt.Errorf("reading prompt file %s: %w", prompt.PromptFile, err)
620				}
621				promptText = string(data)
622			}
623	
624			baseOpts := RunOptions{
625				Prompt:  promptText,
626				Timeout: timeout,
627			}
628	
629			compareOpts := BenchmarkArmsToCompare(suite.Arms, baseOpts)
630			compareOpts.Sandbox = suite.Sandbox
631			compareOpts.PostRun = suite.PostRun
632	
633			record, err := runCompare(compareOpts)
634			if err != nil {
635				return nil, fmt.Errorf("prompt %s: %w", prompt.ID, err)
636			}
637	
638			result.Comparisons = append(result.Comparisons, *record)
639		}
640	
641		result.Summary = benchSummarize(result)
642		return result, nil
643	}
