	}
	env := os.Environ()
	out := make([]string, 0, len(env))
	for _, e := range env {
		key := e
		if i := strings.Index(e, "="); i >= 0 {
			key = e[:i]
		}
		if !blocked[key] {
			out = append(out, e)
		}
	}
	return out
}

